<#
.SYNOPSIS
    ddev
#>
try { docker system prune -f; docker builder prune -f } catch {}; if (docker ps -a --filter "name=dotnet-setup" --format "{{.Names}}" 2>$null | Where-Object { $_ -eq "dotnet-setup" }) { try { if (docker ps --filter "name=dotnet-setup" --format "{{.Names}}" 2>$null | Where-Object { $_ -eq "dotnet-setup" }) { docker stop dotnet-setup 2>$null }; docker commit dotnet-setup developer:latest 2>$null; if (-not (Test-Path "F:\backup\Containers")) { New-Item -Path "F:\backup\Containers" -ItemType Directory -Force | Out-Null }; docker save developer:latest -o "F:\backup\Containers\developer.tar" 2>$null; docker rm dotnet-setup 2>$null; Write-Host "? BACKUP COMPLETE: $([math]::Round(((Get-Item 'F:\backup\Containers\developer.tar').Length / 1GB), 2)) GB saved with ALL changes including .NET 8.0.414" -ForegroundColor Green } catch { Write-Host "?? Container exists but backup failed - attempting cleanup" -ForegroundColor Yellow; try { docker rm -f dotnet-setup 2>$null; docker rmi developer:latest 2>$null } catch {}; docker system prune -f 2>$null } } else { Write-Host "? Container 'dotnet-setup' does not exist" -ForegroundColor Red; docker ps -a --format "table {{.Names}}\t{{.Image}}\t{{.Status}}" 2>$null }
